const d1  = $('Buscar Hoje').first().json;
const d7  = $('Buscar Semana').first().json;
const d30 = $('Buscar 30 dias').first().json;
const d90 = $input.first().json;

function fmt(s) {
  const [y, m, d] = s.split('-');
  return d + '/' + m + '/' + y;
}
function fmtShort(s) {
  const [y, m, d] = s.split('-');
  return d + '/' + m;
}
function brl(v) {
  const num = parseFloat(v) || 0;
  const parts = Math.abs(num).toFixed(2).split('.');
  parts[0] = parts[0].replace(/\B(?=(\d{3})+(?!\d))/g, '.');
  return 'R$ ' + parts[0] + ',' + parts[1];
}
function brl8(v) {
  const num = parseFloat(v) || 0;
  return 'R$ ' + Math.abs(num).toFixed(8).replace('.', ',');
}
function pct(a, b) {
  if (!b) return '0,00';
  return (a / b * 100).toFixed(2).replace('.', ',');
}
function deltaEmoji(v) {
  return parseFloat(v) >= 0 ? '🟢' : '🔴';
}
function deltaLabel(v) {
  return parseFloat(v) >= 0 ? 'positivo' : 'negativo';
}

const meses = ['Jan','Fev','Mar','Abr','Mai','Jun','Jul','Ago','Set','Out','Nov','Dez'];
function fmtMes(s) {
  const [y, m] = s.split('-');
  return meses[parseInt(m, 10) - 1] + '/' + y;
}

// ── Usuários ──────────────────────────────────────────────────────────────────
const u1 = d1.usuarios;
const taxaConversao = Math.round(u1.investindo / u1.total * 100);
const usuariosHoje = u1.novos > 0
  ? '👥 Hoje tivemos ' + u1.novos + ' novos cadastros, totalizando ' + u1.total + ' usuários. Destes, ' + u1.investindo + ' investindo (' + taxaConversao + '% de conversão).'
  : '👥 Sem novos cadastros hoje. Base: ' + u1.total + ' usuários, ' + u1.investindo + ' investindo (' + taxaConversao + '% de conversão).';

function usuariosPeriodo(u) {
  const base = u.total - u.novos;
  return '👥 ' + u.novos + ' novos usuários (+' + pct(u.novos, base) + '%). Total: ' + u.total + ', investindo: ' + u.investindo + '.';
}

// ── Financeiro ────────────────────────────────────────────────────────────────
function finHoje(f) {
  const dEmoji = deltaEmoji(f.delta);
  return '💰 Depósitos: ' + brl(f.depositos) + ' | Saques: ' + brl(f.saques) + '\n' +
         dEmoji + ' Delta ' + deltaLabel(f.delta) + ': ' + brl(f.delta);
}
function finPeriodo(f) {
  const dEmoji = deltaEmoji(f.delta);
  return '💰 Depósitos: ' + brl(f.depositos) + ' | Saques: ' + brl(f.saques) + '\n' +
         dEmoji + ' Delta ' + deltaLabel(f.delta) + ': ' + brl(f.delta);
}

// ── Lulu ──────────────────────────────────────────────────────────────────────
function luluPeriodo(f) {
  const taxas   = brl(f.lulu_taxas_deposito_periodo   || 0);
  const deduzido = brl8(f.lulu_valor_deduzido_periodo || 0);
  return '🏦 Lulu: taxas Efí Bank ' + taxas + ' | deduzido dos rendimentos ' + deduzido;
}

// ── Outros ────────────────────────────────────────────────────────────────────
const pendentes = d1.financeiro.saques_pendentes || 0;
const saquesPendentesLinha = pendentes > 0
  ? '⚠️ Saques pendentes: ' + pendentes
  : '✅ Nenhum saque pendente.';

const volumeInvestido = '💼 Volume total investido: ' + brl(d1.financeiro.volume_investido);

const projecao = (d1.projecao_6_meses || []).map(function(p) {
  return '  ' + fmtMes(p.mes) + ': ' + brl(p.total_previsto);
}).join('\n');

const luluTotalBloco = [
  '🏦 *_Lulu - Total Acumulado_*',
  '',
  '💳 Taxas pagas à Efí Bank: ' + brl(d1.financeiro.lulu_taxas_deposito_total   || 0),
  '🔄 Deduzido dos rendimentos: ' + brl8(d1.financeiro.lulu_valor_deduzido_total || 0),
].join('\n');

// ── Estrutura ─────────────────────────────────────────────────────────────────
const estrutura = [
  '📋 *_Resumo Operacional - ' + fmt(d1.data_referencia) + '_*',
  '',
  '📅 *_Hoje_*',
  '',
  usuariosHoje,
  '',
  volumeInvestido,
  '',
  finHoje(d1.financeiro),
  '',
  luluPeriodo(d1.financeiro),
  '',
  saquesPendentesLinha,
  '',
  '📅 *_Últimos 7 dias_* (' + fmtShort(d7.data_inicio) + ' a ' + fmtShort(d7.data_referencia) + ')',
  '',
  usuariosPeriodo(d7.usuarios),
  '',
  finPeriodo(d7.financeiro),
  '',
  luluPeriodo(d7.financeiro),
  '',
  '📅 *_Últimos 30 dias_* (' + fmtShort(d30.data_inicio) + ' a ' + fmtShort(d30.data_referencia) + ')',
  '',
  usuariosPeriodo(d30.usuarios),
  '',
  finPeriodo(d30.financeiro),
  '',
  luluPeriodo(d30.financeiro),
  '',
  '📅 *_Últimos 90 dias_* (' + fmtShort(d90.data_inicio) + ' a ' + fmtShort(d90.data_referencia) + ')',
  '',
  usuariosPeriodo(d90.usuarios),
  '',
  finPeriodo(d90.financeiro),
  '',
  luluPeriodo(d90.financeiro),
  '',
  luluTotalBloco,
  '',
  '📈 *_Projeção das Metas (6 meses)_*',
  '',
  projecao || 'Nenhuma meta ativa configurada.',
].join('\n');

const chatInput = [
  'Voce e um assistente executivo da Purg.',
  'Com base nos dados abaixo, escreva EXATAMENTE 2 paragrafos curtos e suscintos de analise comparativa.',
  'Cada paragrafo deve ter no maximo 2 frases. Cubra angulos diferentes: um sobre usuarios, outro sobre financeiro.',
  'Regras: texto simples, sem asteriscos, sem markdown, sem introducao, sem assinatura.',
  '',
  estrutura,
].join('\n');

return [{ json: { estrutura, chatInput } }];

